module.render:
const body = sections[0] ? sections[0].trim() : '';
const color = (args.color && String(args.color).trim()) || '#fde68a';
const textcolor = args.textcolor && String(args.textcolor).trim();
const radius = args.radius && String(args.radius).trim();
const bold = String(args.bold) === 'true';
let style = 'background-color: ' + color + ';';
if (textcolor) style += ' color: ' + textcolor + ';';
if (radius) style += ' border-radius: ' + radius + ';';
if (bold) style += ' font-weight: 700;';
return '<span class="mdp-mod-mark" style="' + style + '">' + body + '</span>';
